/**
 * Calculates the loyalty discount based on the Q4 2024 promotion rules:
 * - Gold-tier customers get 15% off orders over $500 with 4+ items
 * - This incentivizes bulk purchases from our best customers
 * - Promotion approved in PROMO-4567, expires 2025-03-31
 */
public BigDecimal calculateDiscount(Order order) {
    boolean isEligible = order.getTotal().compareTo(BULK_THRESHOLD) > 0
        && order.getCustomerTier().equals(GOLD_TIER)
        && order.getItemsCount() > MIN_ITEMS_FOR_DISCOUNT;
    return isEligible
        ? order.getTotal().multiply(LOYALTY_DISCOUNT_RATE)
        : BigDecimal.ZERO;
}
